import{_ as e,o as s,c as o,a2 as i}from"./chunks/framework.BKG_UbFK.js";const h=JSON.parse('{"title":"Migrar a partir de uma instalação Spatie existente","description":"","frontmatter":{},"headers":[],"relativePath":"pt/guide/migration.md","filePath":"pt/guide/migration.md"}'),t={name:"pt/guide/migration.md"};function d(r,a,c,l,n,p){return s(),o("div",null,[...a[0]||(a[0]=[i(`<h1 id="migrar-a-partir-de-uma-instalacao-spatie-existente" tabindex="-1">Migrar a partir de uma instalação Spatie existente <a class="header-anchor" href="#migrar-a-partir-de-uma-instalacao-spatie-existente" aria-label="Permalink to &quot;Migrar a partir de uma instalação Spatie existente&quot;">​</a></h1><p>Se a sua aplicação já usa <code>spatie/laravel-permission</code> com papéis, permissões e atribuições existentes, o <code>clearance:install</code> deteta-os e preserva-os - nunca executa as migrações do Spatie se a tabela <code>roles</code> já existir. Ver <a href="/clearance-docs/pt/guide/installation.html">Instalação</a> para o fluxo de instalação completo.</p><p>Após a instalação, use <code>clearance:backfill</code> para adotar os próprios metadados do Clearance nos seus papéis e guards existentes.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # meta + role scope + guards</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --only=meta</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # just one section</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dry-run</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # preview, no writes</span></span></code></pre></div><h2 id="o-que-cada-seccao-faz" tabindex="-1">O que cada secção faz <a class="header-anchor" href="#o-que-cada-seccao-faz" aria-label="Permalink to &quot;O que cada secção faz&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Secção</th><th>Efeito</th></tr></thead><tbody><tr><td><code>meta</code></td><td>Semeia um nome de exibição <code>clr_meta</code> (nome do papel em title-case) para todos os papéis que não tenham um.</td></tr><tr><td><code>roles</code></td><td>Semeia os padrões de <code>clr_role_meta</code> (<code>scope=global</code>, <code>is_locked=false</code>) para todos os papéis que não tenham um.</td></tr><tr><td><code>guards</code></td><td>Importa guards de <code>config(&#39;auth.guards&#39;)</code> para <code>clr_guards</code>, filtrados por <code>allowed_guard_drivers</code>.</td></tr></tbody></table><p>Use <code>--only=&lt;section&gt;</code> para executar uma única secção em vez das três.</p><div class="tip custom-block"><p class="custom-block-title">Idempotente</p><p>Todas as secções são idempotentes - executar <code>clearance:backfill</code> novamente é seguro e não duplicará nem sobrescreverá linhas <code>clr_*</code> existentes.</p></div><h2 id="casos-limite" tabindex="-1">Casos limite <a class="header-anchor" href="#casos-limite" aria-label="Permalink to &quot;Casos limite&quot;">​</a></h2><p>O repositório do pacote tem um guia de migração mais aprofundado que cobre casos limite não resumidos aqui - nomeadamente o que acontece quando a sua base de dados já tem um papel chamado <code>super_admin</code> (ou um alias como <code>superadmin</code>, <code>root</code>, <code>owner</code>) que colide com o próprio papel <code>super_admin</code> do Clearance, e notas sobre subclasses de modelo <code>Role</code>/<code>Permission</code> personalizadas e o comportamento de importação de guards. Leia-o antes de fazer o backfill de uma base de dados de produção com dados de papéis existentes não triviais. Ver também <a href="/clearance-docs/pt/features/super-admin.html">Super Admin</a> para o comportamento de deteção de aliases durante o <code>clearance:install</code>.</p><h2 id="relacionado" tabindex="-1">Relacionado <a class="header-anchor" href="#relacionado" aria-label="Permalink to &quot;Relacionado&quot;">​</a></h2><ul><li><a href="/clearance-docs/pt/guide/installation.html">Instalação</a> - o fluxo completo do <code>clearance:install</code></li><li><a href="/clearance-docs/pt/api/artisan-commands.html">Comandos Artisan</a> - referência completa de comandos</li><li><a href="/clearance-docs/pt/guide/architecture.html">Arquitetura</a> - as tabelas <code>clr_*</code> que o backfill preenche</li></ul>`,12)])])}const u=e(t,[["render",d]]);export{h as __pageData,u as default};
